        require(voter != address(0), "Invalid address");
        require(!votersWithRights[voter], "Voting rights already granted");
        votersWithRights[voter] = true;
        emit VotingRightsGranted(voter);
    }

    function hasVotingRights(address voter) public view returns (bool) {
        return votersWithRights[voter];
    }

